from dataclasses import dataclass
from enum import IntEnum

class Severity(IntEnum):
    P0 = 0; P1 = 1; P2 = 2; P3 = 3; P4 = 4

@dataclass
class Classification:
    incident_type: str
    floor_severity: Severity
    step_resolved: int   # which step produced the answer (1-6)

def run_decision_tree(s) -> Classification:
    # Step 1: safety / privacy
    if s.safety_pipeline_flag: return Classification("safety/policy-violation",    Severity.P0, 1)
    if s.guardrail_probe_fail:  return Classification("safety/guardrail-bypass",    Severity.P0, 1)
    if s.injection_detected:    return Classification("safety/prompt-injection",    Severity.P0, 1)
    if s.session_bleed:         return Classification("data/session-bleed",         Severity.P0, 1)
    if s.pii_leak:              return Classification("data/pii-leakage",           Severity.P0, 1)
    if s.data_pipeline_leak:    return Classification("data/pipeline-failure",      Severity.P0, 1)

    # Step 2: error rate
    if s.error_rate_pct > 25:
        return Classification("availability/complete-outage",    Severity.P0, 2)
    if s.error_rate_pct > 5 or s.customer_scope_pct > 20:
        return Classification("availability/partial-degradation", Severity.P1, 2)
    if s.error_rate_pct > 1:
        return Classification("availability/partial-degradation", Severity.P2, 2)

    # Step 3: latency
    if s.latency_ratio > 5:
        return Classification("availability/latency-regression",  Severity.P0, 3)
    if s.latency_ratio > 2:
        return Classification("availability/latency-regression",  Severity.P1, 3)
    if s.latency_ratio > 1.5:
        return Classification("availability/latency-regression",  Severity.P2, 3)

    # Step 4: infrastructure
    if not s.serving_health_ok:
        return Classification("infrastructure/model-serving",      Severity.P1, 4)
    if s.dependency_error_pct > 5:
        return Classification("infrastructure/dependency-failure", Severity.P1, 4)
    if s.queue_reject_rate > 0.01:
        return Classification("infrastructure/capacity-exhaustion",Severity.P1, 4)

    # Step 5: quality
    if s.quality_score_drop > 0.10:
        return Classification("model-quality/quality-degradation", Severity.P1, 5)
    if s.quality_score_drop > 0.05:
        return Classification("model-quality/hallucination-spike", Severity.P2, 5)

    # Step 6: default
    sev = Severity.P3 if s.customer_reported else Severity.P4
    return Classification("unclassified", sev, 6)

from fastapi import FastAPI, Request
import httpx

app = FastAPI()
PAGERDUTY_API = "https://api.pagerduty.com/incidents"

@app.post("/webhook/alert")
async def handle_alert(req: Request):
    payload = await req.json()
    signals = gather_signals()        # pulls Prometheus queries
    classification = run_decision_tree(signals)

    # Annotate the PagerDuty incident with classification result
    incident_id = payload["incident"]["id"]
    async with httpx.AsyncClient() as client:
        await client.put(
            f"{PAGERDUTY_API}/{incident_id}",
            json={
                "incident": {
                    "custom_fields": {
                        "incident_type":   classification.incident_type,
                        "floor_severity":  classification.floor_severity.name,
                        "step_resolved":   str(classification.step_resolved),
                    }
                }
            },
            headers={"Authorization": f"Token token={PAGERDUTY_API_KEY}"},
        )
    return {"status": "classified", "type": classification.incident_type}
